var dateFirstPay = Services.getValue(DateOfFirstPayment.dataBinding);
var dateFirstPayObj = CaseManUtils.isBlank(dateFirstPay) ? null : CaseManUtils.createDate(dateFirstPay);
var ec = null;
if(dateFirstPayObj != null){
  ec = validateFirstPaymentDate(dateFirstPayObj);     
}
return ec;

Javascript.miscCode:
function validateFirstPaymentDate(dateObj)
{    
  var todayDateObj = CaseManUtils.createDate(getTodaysDate());
  var errCode = null;
  var comparison = CaseManUtils.compareDates(dateObj, todayDateObj);
  if(comparison == 1 || comparison == 0){
    errCode = ErrorCode.getErrorCode("CaseMan_dateCanOnlyBeInTheFuture_Msg");
  }     
  return errCode;   
}
